SELECT A.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , B.SSVC_GROUP_CD -- 센터/본부_CD , B.SSVC_OBJ_CD -- 노드_CD , B.SASSIGN_TYPE_CD -- IP할당유형_CD , B.SSUBSCNESCODE -- 시설코드 , B.SNEALIAS -- 장비명 , B.DCREATE_DT , B.SCREATE_ID , B.DMODIFY_DT , B.SMODIFY_ID FROM MST.TB_SVC_LINE_TYPE_CD A , MST.TB_INTGRM_DEFAULT_SVC_MST B WHERE 1=1 AND A.SSVC_LINE_TYPE_CD IN ('CL0001', 'CL0002', 'CL0003') AND B.SSVC_LINE_TYPE_CD(+) = A.SSVC_LINE_TYPE_CD
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
ORDER BY A.SSVC_LINE_TYPE_CD

SELECT A.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , B.SSVC_GROUP_CD -- 센터/본부_CD , B.SSVC_OBJ_CD -- 노드_CD , B.SASSIGN_TYPE_CD -- IP할당유형_CD , B.SSUBSCNESCODE -- 시설코드 , B.SNEALIAS -- 장비명 , B.DCREATE_DT , B.SCREATE_ID , B.DMODIFY_DT , B.SMODIFY_ID FROM MST.TB_SVC_LINE_TYPE_CD A , MST.TB_INTGRM_DEFAULT_SVC_MST B WHERE 1=1 AND A.SSVC_LINE_TYPE_CD IN ('CL0001', 'CL0002', 'CL0003') AND B.SSVC_LINE_TYPE_CD = A.SSVC_LINE_TYPE_CD
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
ORDER BY A.SSVC_LINE_TYPE_CD

mapper.insert:
INSERT
INTO MST.TB_INTGRM_DEFAULT_SVC_MST (
	SSVC_LINE_TYPE_CD
	,   SSVC_GROUP_CD	-- 센터/본부_CD
	,   SSVC_OBJ_CD		-- 노드_CD
	,   SASSIGN_TYPE_CD -- IP할당유형_CD
	,   SSUBSCNESCODE	-- 시설코드
	,   SNEALIAS -- 장비명
	,	SCREATE_ID
	,	SMODIFY_ID

) VALUES (
	#{ssvcLineTypeCd, jdbcType=CHAR}
	,	#{ssvcGroupCd, jdbcType=CHAR}
	,	#{ssvcObjCd, jdbcType=CHAR}
	,	#{sassignTypeCd, jdbcType=CHAR}
	,	#{ssubsnescode, jdbcType=VARCHAR}
	,	#{snealias, jdbcType=VARCHAR}
	,	#{screateId, jdbcType=VARCHAR}
	,	#{smodifyId, jdbcType=VARCHAR}
)

mapper.update:
UPDATE 
	MST.TB_INTGRM_DEFAULT_SVC_MST A  
SET

		A.SSVC_GROUP_CD = #{ssvcGroupCd, jdbcType=CHAR}


		, A.SSVC_OBJ_CD = #{ssvcObjCd, jdbcType=CHAR}


		, A.SASSIGN_TYPE_CD = #{sassignTypeCd, jdbcType=CHAR}


		, A.SSUBSCNESCODE = #{ssubsnescode, jdbcType=VARCHAR}


		, A.SNEALIAS = #{snealias, jdbcType=VARCHAR}


		, A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}

		, A.DMODIFY_DT = SYSDATE
WHERE 1=1
	     AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
